from dataclasses import dataclass, field
from typing import Literal

BarrierType = Literal["ACCESS", "SKILL", "TRUST", "CULTURE", "WORKFLOW_FIT", "UNKNOWN"]

SURVEY_OPTION_MAP = {
    "a": "ACCESS",
    "b": "SKILL",
    "c": "TRUST",
    "d": "CULTURE",
    "e": "WORKFLOW_FIT",
    "f": "UNKNOWN",
}

@dataclass
class BarrierSurveyResponse:
    respondent_id: str
    business_unit: str
    role: str
    primary_barrier_option: str     # "a" through "f"
    free_text: str = ""

    def barrier_type(self) -> BarrierType:
        return SURVEY_OPTION_MAP.get(self.primary_barrier_option, "UNKNOWN")

@dataclass
class BarrierAnalysis:
    responses: list[BarrierSurveyResponse]

    def barrier_distribution(self, bu: str = None) -> dict[BarrierType, float]:
        subset = [r for r in self.responses if bu is None or r.business_unit == bu]
        if not subset:
            return {}
        counts: dict[str, int] = {}
        for r in subset:
            bt = r.barrier_type()
            counts[bt] = counts.get(bt, 0) + 1
        total = len(subset)
        return {bt: count / total * 100 for bt, count in sorted(counts.items(), key=lambda x: -x[1])}

    def primary_barrier(self, bu: str = None) -> BarrierType:
        dist = self.barrier_distribution(bu)
        if not dist:
            return "UNKNOWN"
        return max(dist, key=dist.get)

    def intervention_priority(self, bu: str = None) -> list[str]:
        dist = self.barrier_distribution(bu)
        interventions = {
            "ACCESS":       "Escalate IT provisioning; set 5-day SLA; simplify compliance module",
            "SKILL":        "Deploy champion buddy for 30 days; run role-specific workshop; publish prompt library",
            "TRUST":        "Publish verification checklist; run 'errors we caught' session; reframe AI as co-pilot",
            "CULTURE":      "Brief line managers; get exec sponsor message; run peer-led quick-win demo",
            "WORKFLOW_FIT": "Run use case discovery session; if no fit found, stop measuring as adoption failure",
            "UNKNOWN":      "Review free-text responses; conduct 5 user interviews for richer signal",
        }
        return [
            f"{bt} ({pct:.0f}%): {interventions[bt]}"
            for bt, pct in dist.items()
            if pct > 10  # report only barriers affecting > 10% of respondents
        ]

# Example
analysis = BarrierAnalysis(responses=[
    BarrierSurveyResponse("U001", "Finance BU", "Analyst", "b"),
    BarrierSurveyResponse("U002", "Finance BU", "Analyst", "b"),
    BarrierSurveyResponse("U003", "Finance BU", "Manager", "c"),
    BarrierSurveyResponse("U004", "Legal BU",   "Counsel", "d"),
    BarrierSurveyResponse("U005", "Legal BU",   "Counsel", "e"),
    BarrierSurveyResponse("U006", "Legal BU",   "Counsel", "d"),
])
print("Finance primary barrier:", analysis.primary_barrier("Finance BU"))
print("Legal primary barrier:  ", analysis.primary_barrier("Legal BU"))
print()
print("Finance interventions:", analysis.intervention_priority("Finance BU"))
print("Legal interventions:  ", analysis.intervention_priority("Legal BU"))
# Finance primary barrier: SKILL
# Legal primary barrier:   CULTURE
# Finance: SKILL (67%): Deploy champion buddy; role-specific workshop; prompt library
# Legal: CULTURE (67%): Brief line managers; exec sponsor message; peer-led demo
#        WORKFLOW_FIT (33%): Run use case discovery session...

@dataclass
class WorkflowFitAssessment:
    role: str
    business_unit: str
    tasks_assessed: list[str]
    tasks_with_plausible_fit: list[str]
    minimum_fit_threshold: int = 2

    def has_sufficient_fit(self) -> bool:
        return len(self.tasks_with_plausible_fit) >= self.minimum_fit_threshold

    def recommendation(self) -> str:
        if self.has_sufficient_fit():
            top_two = self.tasks_with_plausible_fit[:2]
            return (
                f"Sufficient fit found. Focus onboarding on: {'; '.join(top_two)}. "
                f"Do not attempt to use tool for other tasks until these are embedded."
            )
        return (
            f"Insufficient fit for current GenAI tools in {self.role} / {self.business_unit}. "
            f"Recommend: (1) Pause adoption target for this role; "
            f"(2) Revisit in 6 months as tool capabilities evolve; "
            f"(3) Do not count non-adoption as programme failure in reporting."
        )

assessment = WorkflowFitAssessment(
    role="Senior Legal Counsel",
    business_unit="Legal BU",
    tasks_assessed=[
        "Client contract drafting",
        "Regulatory compliance memo",
        "Internal policy summary",
        "Meeting notes from internal sessions",
        "Research summarisation for non-privileged sources",
    ],
    tasks_with_plausible_fit=[
        "Internal policy summary",
        "Meeting notes from internal sessions",
    ],
)
print(assessment.recommendation())
# Sufficient fit found. Focus onboarding on: Internal policy summary; Meeting notes from internal sessions.
# Do not attempt to use tool for other tasks until these are embedded.

from dataclasses import dataclass
from typing import Literal

BarrierType = Literal["ACCESS", "SKILL", "TRUST", "CULTURE", "WORKFLOW_FIT"]

SEQUENCING_PRIORITY = {
    "ACCESS": 1,
    "CULTURE": 2,
    "TRUST": 3,
    "SKILL": 3,
    "WORKFLOW_FIT": 4,
}

@dataclass
class CompoundBarrierPlan:
    identified_barriers: list[BarrierType]

    def intervention_sequence(self) -> list[tuple[int, BarrierType]]:
        """Return barriers ordered by intervention priority."""
        return sorted(
            [(SEQUENCING_PRIORITY[b], b) for b in self.identified_barriers],
            key=lambda x: x[0]
        )

    def sprint_plan(self) -> list[str]:
        """Map each barrier to a 2-week sprint."""
        sequence = self.intervention_sequence()
        plan = []
        # Group same-priority barriers into the same sprint
        from itertools import groupby
        for priority, group in groupby(sequence, key=lambda x: x[0]):
            barriers = [b for _, b in group]
            sprint_num = priority
            if len(barriers) == 1:
                plan.append(f"Sprint {sprint_num}: Resolve {barriers[0]} barrier")
            else:
                plan.append(f"Sprint {sprint_num}: Resolve {' + '.join(barriers)} barriers in parallel")
        return plan

# Legal team with compound barriers
plan = CompoundBarrierPlan(identified_barriers=["CULTURE", "WORKFLOW_FIT", "SKILL"])
for step in plan.sprint_plan():
    print(step)
# Sprint 2: Resolve CULTURE barrier
# Sprint 3: Resolve SKILL barrier
# Sprint 4: Resolve WORKFLOW_FIT barrier
